import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Claude Code /effort Max 設定上線 — @trq212","description":"","frontmatter":{"title":"Claude Code /effort Max 設定上線 — @trq212","author":"Thariq（@trq212）","date":"2026-03-14T00:00:00.000Z","source":"https://x.com/trq212/status/2032632596572811575","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-14-@trq212-811575.md","filePath":"research/tweets/2026-03-14-@trq212-811575.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-03-14-@trq212-811575.md"};function d(n,t,i,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-code-effort-max-設定上線-—-trq212" tabindex="-1">Claude Code /effort Max 設定上線 — @trq212 <a class="header-anchor" href="#claude-code-effort-max-設定上線-—-trq212" aria-label="Permalink to &quot;Claude Code /effort Max 設定上線 — @trq212&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/trq212/status/2032632596572811575" target="_blank" rel="noreferrer">https://x.com/trq212/status/2032632596572811575</a><strong>作者</strong>：Thariq（@trq212） <strong>發布日期</strong>：2026-03-14 <strong>收錄日期</strong>：2026-05-16 <strong>類型</strong>：一般推文（功能公告） <strong>統計</strong>：3096 likes · 180 retweets · 1308 bookmarks · 643444 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>A few end of week ships:</p><p>You can now set effort to &#39;max&#39; which reasons for longer and uses as many tokens as needed. This will spend your usage limits more quickly so you have to activate it per session.</p><p>Hit /effort to try it.</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>/effort max 指令上線：讓 Claude 推理更久、用更多 token，每 session 需手動啟用，會更快消耗用量上限。</p><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>新指令</strong>：<code>/effort</code> — 設定推理深度</li><li><strong>max 模式</strong>：不設 token 上限，盡可能長推理</li><li><strong>per-session 啟用</strong>：不是持久設定，每次 session 需要手動開</li><li><strong>用量影響</strong>：會更快消耗 usage limits，需注意</li></ol><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>功能宣告性質</strong>：無使用場景建議，何時用 max 何時不用缺乏指引</li><li><strong>高 views 但適中 bookmark</strong>：643k views，bookmark rate 0.2%，可能主要是知曉型閱讀</li><li><strong>與 token budget 規則相關</strong>：cc-workspace 的 context-management.md 有 per-task/per-session token budget；max effort 可能衝突</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>6/10</td><td>可立即使用，但缺乏何時使用的指引</td></tr><tr><td>B. 創新性 (20%)</td><td>4/10</td><td>功能宣告</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>無使用案例或效果數據</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>一句話描述，無細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>6/10</td><td>適用需要深度推理的任務</td></tr><tr><td><strong>加權總分</strong></td><td><strong>4.75/10</strong></td><td>6×0.3+4×0.2+4×0.2+3×0.15+6×0.15 = 1.80+0.80+0.80+0.45+0.90</td></tr></tbody></table><p><strong>整合決策</strong>：Skip（僅歸檔） <strong>理由</strong>：分數 4.75 &lt; 6；功能宣告無深度技術內容</p>',18)])])}const u=e(s,[["render",d]]);export{f as __pageData,u as default};
